describe('FileEntry', () => {
  it('decodes entry without oldPath', () => {
    const result = Schema.decodeUnknownSync(FileEntry)({ path: 'a.ts', changeType: 'modified' });
    expect(result).toEqual({ path: 'a.ts', changeType: 'modified' });
  });

  it('decodes entry with oldPath', () => {
    const result = Schema.decodeUnknownSync(FileEntry)({ path: 'b.ts', changeType: 'renamed', oldPath: 'a.ts' });
    expect(result).toEqual({ path: 'b.ts', changeType: 'renamed', oldPath: 'a.ts' });
  });
});
```

